queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasVendors ?child ; p:hasCraft_Fairs ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Craft_Fairs } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasVendors ?child ; p:hasCraft_Fairs ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Craft_Fairs } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?type WHERE {
  ?craft_fairs_vendors a :Craft_Fairs_Vendors .
  ?vendors a :Vendors .
  ?craft_fairs_vendors p:hasVendors ?vendors .
  ?craft_fairs a :Craft_Fairs .
  ?craft_fairs_vendors p:hasCraft_Fairs ?craft_fairs .
  ?craft_fairs p:name ?name .
  ?vendors p:type ?type .
} }
}
